local filename = ngx.var.arg_filename
if not filename then
    ngx.status = 400
    ngx.say("Filename parameter required")
    ngx.exit(400)
end

local file_path = "./files/" .. filename
local file = io.open(file_path, "r")
if not file then
    ngx.status = 404
    ngx.say("File not found")
    ngx.exit(404)
